interface RestaurantProps {
  name: string;
  status: string;
  cuisine: string;
  rating: number;
  imageUrl: string;
}

export default function RestaurantCard({ name, status, cuisine, rating, imageUrl }: RestaurantProps) {
  return (
    <div className="flex items-center justify-between bg-[#D9D9D9] rounded-[20px] p-4 w-full max-w-[350px] shadow-sm mb-4">
      <div className="flex flex-col">
        <h3 className="font-bold text-lg leading-tight">{name}</h3>
        <p className="text-sm">{status}</p>
        <p className="text-sm">{cuisine}</p>
        <div className="flex mt-1">
          {Array.from({ length: 5 }).map((_, i) => (
            <span key={i} className="text-sm">
              {i < rating ? "★" : "☆"}
            </span>
          ))}
        </div>
      </div>
      
      <div className="flex flex-col items-end gap-2">
        <img 
          src={imageUrl} 
          alt={name} 
          className="w-24 h-16 rounded-lg object-cover bg-gray-400" 
        />
        <button className="bg-[#B7B7B7] text-[10px] px-3 py-1 rounded-md flex items-center gap-1 hover:bg-gray-400 transition">
          Directions <span>→</span>
        </button>
      </div>
    </div>
  )
}